namespace sv_547ecd353e2b404dbbed9bd8cf0259bc.Client.Models;

public sealed class Shipment
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public DateTimeOffset? EstimatedDelivery { get; init; }
    public required List<StatusUpdate> Updates { get; init; }
}

public sealed class StatusUpdate
{
    public required DateTimeOffset Timestamp { get; init; }
    public required string Description { get; init; }
    public string? Location { get; init; }
}

using sv_547ecd353e2b404dbbed9bd8cf0259bc.Client.Models;

namespace sv_547ecd353e2b404dbbed9bd8cf0259bc.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using System.Net.Http.Json;
using sv_547ecd353e2b404dbbed9bd8cf0259bc.Client.Models;

namespace sv_547ecd353e2b404dbbed9bd8cf0259bc.Client.Services;

/// <summary>
/// Client-side implementation that calls the server API over HTTP.
/// Used when running in WebAssembly render mode.
/// </summary>
public sealed class ShipmentService(HttpClient http) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();

        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

using sv_547ecd353e2b404dbbed9bd8cf0259bc.Client.Models;
using sv_547ecd353e2b404dbbed9bd8cf0259bc.Client.Services;

namespace sv_547ecd353e2b404dbbed9bd8cf0259bc.Services;

/// <summary>
/// Server-side implementation with simulated slow backend and seeded data.
/// </summary>
public sealed class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> Seeds = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new Shipment
        {
            TrackingNumber = "TRK-001",
            Status = "In Transit",
            Location = "Memphis, TN",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 25, 17, 0, 0, TimeSpan.Zero),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 20, 9, 0, 0, TimeSpan.Zero), Description = "Package picked up", Location = "Los Angeles, CA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 21, 14, 30, 0, TimeSpan.Zero), Description = "Arrived at sorting facility", Location = "Phoenix, AZ" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 22, 6, 15, 0, TimeSpan.Zero), Description = "Departed facility", Location = "Memphis, TN" },
            ]
        },
        ["TRK-002"] = new Shipment
        {
            TrackingNumber = "TRK-002",
            Status = "Delivered",
            Location = "New York, NY",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 21, 12, 0, 0, TimeSpan.Zero),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 18, 10, 0, 0, TimeSpan.Zero), Description = "Package picked up", Location = "Chicago, IL" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 19, 22, 0, 0, TimeSpan.Zero), Description = "In transit", Location = "Columbus, OH" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 20, 16, 45, 0, TimeSpan.Zero), Description = "Out for delivery", Location = "New York, NY" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 20, 18, 12, 0, TimeSpan.Zero), Description = "Delivered", Location = "New York, NY" },
            ]
        },
        ["TRK-003"] = new Shipment
        {
            TrackingNumber = "TRK-003",
            Status = "Processing",
            Location = "Seattle, WA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 20, 0, 0, TimeSpan.Zero),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 22, 8, 0, 0, TimeSpan.Zero), Description = "Order received", Location = "Seattle, WA" },
            ]
        }
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        Seeds.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@using sv_547ecd353e2b404dbbed9bd8cf0259bc.Client.Models
@using sv_547ecd353e2b404dbbed9bd8cf0259bc.Client.Services
@rendermode InteractiveAuto
@implements IDisposable
@inject IShipmentService ShipmentService
@inject ILogger<Shipment> Logger

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>…</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="not-found">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            @if (_shipment.EstimatedDelivery.HasValue)
            {
                <dt>Estimated Delivery</dt>
                <dd>@_shipment.EstimatedDelivery.Value.ToString("f")</dd>
            }
        </dl>

        @if (_shipment.Updates.Count > 0)
        {
            <h3>Tracking History</h3>
            <ul class="tracking-history">
                @foreach (var update in _shipment.Updates.OrderByDescending(u => u.Timestamp))
                {
                    <li>
                        <time datetime="@update.Timestamp.ToString("o")">@update.Timestamp.ToString("g")</time>
                        &mdash; @update.Description
                        @if (update.Location is not null)
                        {
                            <span class="update-location">(@update.Location)</span>
                        }
                    </li>
                }
            </ul>
        }
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private Models.Shipment? _shipment;
    private bool _loading = true;
    private string? _errorMessage;

    private CancellationTokenSource _cts = new();
    private string? _lastLoadedTrackingNumber;

    protected override async Task OnParametersSetAsync()
    {
        // If the tracking number hasn't changed, skip reload
        if (string.Equals(_lastLoadedTrackingNumber, TrackingNumber, StringComparison.OrdinalIgnoreCase)
            && !_loading && _errorMessage is null)
        {
            return;
        }

        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        await _cts.CancelAsync();
        _cts.Dispose();
        _cts = new CancellationTokenSource();

        _lastLoadedTrackingNumber = TrackingNumber;
        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, _cts.Token);
        }
        catch (OperationCanceledException)
        {
            // Request was cancelled (navigation or dispose) — do nothing
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (HttpRequestException ex)
        {
            Logger.LogError(ex, "Network error fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "A network error occurred. Please check your connection and try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Unexpected error fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryLoad()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts.Cancel();
        _cts.Dispose();
    }
}

