{"path": "/tmp/sv-547ecd353e2b404dbbed9bd8cf0259bc/sv-547ecd353e2b404dbbed9bd8cf0259bc.Client/Pages/Shipment.razor", "file_text": "@page "/shipments/{TrackingNumber}"
@using sv_547ecd353e2b404dbbed9bd8cf0259bc.Client.Models
@using sv_547ecd353e2b404dbbed9bd8cf0259bc.Client.Services
@rendermode InteractiveAuto
@implements IDisposable
@inject IShipmentService ShipmentService
@inject ILogger<Shipment> Logger

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>…</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="not-found">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            @if (_shipment.EstimatedDelivery.HasValue)
            {
                <dt>Estimated Delivery</dt>
                <dd>@_shipment.EstimatedDelivery.Value.ToString("f")</dd>
            }
        </dl>

        @if (_shipment.Updates.Count > 0)
        {
            <h3>Tracking History</h3>
            <ul class="tracking-history">
                @foreach (var update in _shipment.Updates.OrderByDescending(u => u.Timestamp))
                {
                    <li>
                        <time datetime="@update.Timestamp.ToString("o")">@update.Timestamp.ToString("g")</time>
                        &mdash; @update.Description
                        @if (update.Location is not null)
                        {
                            <span class="update-location">(@update.Location)</span>
                        }
                    </li>
                }
            </ul>
        }
    </div>
}

